import{o as e,c as a,a as i}from"./app.dbae0759.js";const t='{"title":"Company settings","description":"","frontmatter":{},"headers":[{"level":2,"title":"Main settings","slug":"main-settings"},{"level":3,"title":"Company info","slug":"company-info"},{"level":3,"title":"Interface settings","slug":"interface-settings"},{"level":2,"title":"Licenses","slug":"licenses"},{"level":2,"title":"Styles","slug":"styles"},{"level":2,"title":"Projects","slug":"projects"},{"level":2,"title":"Users","slug":"users"},{"level":2,"title":"Production Lines","slug":"production-lines"},{"level":2,"title":"Tekla Plugin Licenses","slug":"tekla-plugin-licenses"},{"level":2,"title":"Work Calendar","slug":"work-calendar"},{"level":2,"title":"IFC Parsing Setup (IFCPS)","slug":"ifc-parsing-setup-ifcps"},{"level":2,"title":"Machines","slug":"machines"}],"relativePath":"company.md","lastUpdated":1631020647632}',s={},n=[i('<h1 id="company-settings"><a class="header-anchor" href="#company-settings" aria-hidden="true">#</a> Company settings</h1><p><div class="table-of-contents"><ul><li><a href="#main-settings">Main settings</a><ul><li><a href="#company-info">Company info</a></li><li><a href="#interface-settings">Interface settings</a></li></ul></li><li><a href="#licenses">Licenses</a></li><li><a href="#styles">Styles</a></li><li><a href="#projects">Projects</a></li><li><a href="#users">Users</a></li><li><a href="#production-lines">Production Lines</a></li><li><a href="#tekla-plugin-licenses">Tekla Plugin Licenses</a></li><li><a href="#work-calendar">Work Calendar</a></li><li><a href="#ifc-parsing-setup-ifcps">IFC Parsing Setup (IFCPS)</a></li><li><a href="#machines">Machines</a></li></ul></div></p><p>In the company settings view, company managers and admins can tweak several settings.</p><h2 id="main-settings"><a class="header-anchor" href="#main-settings" aria-hidden="true">#</a> Main settings</h2><h3 id="company-info"><a class="header-anchor" href="#company-info" aria-hidden="true">#</a> Company info</h3><p>Company info such a as address, name and email are shown on reports, mails and other templates. Company notifications are sent to the &quot;contact email&quot;.</p><h3 id="interface-settings"><a class="header-anchor" href="#interface-settings" aria-hidden="true">#</a> Interface settings</h3><ul><li>Show QR button: Show a button in the panel viewer that gives the user a QR for the panel.</li><li>Show RFID button: Show a button in the panel viewer that gives the option to register RFID tags.</li><li>Hide &quot;hidden materials&quot; in 3D: Based on the IFC PS config, a part can be detected as hidden material. Those parts can be hidden in the 3D view by default (when you have this checkbox marked).</li><li>Language: This is the default language for the app. Users can change the language if they are allowed by the admin (see the Users table).</li></ul><h2 id="licenses"><a class="header-anchor" href="#licenses" aria-hidden="true">#</a> Licenses</h2><p>Gives a main overview of the licensing.</p><h2 id="styles"><a class="header-anchor" href="#styles" aria-hidden="true">#</a> Styles</h2><p>Corporate color and logos can be changed. Those will be used also in PDF generation. Sticker banner is a wide logo to be used in some of the sticker presets (like panel QR stickers).</p><h2 id="projects"><a class="header-anchor" href="#projects" aria-hidden="true">#</a> Projects</h2><p>Projects are fabrication sets that we recommend don&#39;t get more than 100 designs and 500 panels for performance reasons. The more panels in a project, the slower the interface gets.</p><p>We know that there are some large or very large projects that doesn&#39;t fit on those numbers, so we introduced the &quot;superproject&quot; parameter, so you can group several projects under the same key name. For example, you may have a big project with 10 buildings, and you may want to split it into 10 projects that belong to the same superproject.</p><p>Projects can be &quot;archived&quot; 🗃. Archived project are hidden from the user, and only visible in the archive. We plan a feature to export all the information of an archived project in a .zip file.</p><h2 id="users"><a class="header-anchor" href="#users" aria-hidden="true">#</a> Users</h2><h2 id="production-lines"><a class="header-anchor" href="#production-lines" aria-hidden="true">#</a> Production Lines</h2><h2 id="tekla-plugin-licenses"><a class="header-anchor" href="#tekla-plugin-licenses" aria-hidden="true">#</a> Tekla Plugin Licenses</h2><h2 id="work-calendar"><a class="header-anchor" href="#work-calendar" aria-hidden="true">#</a> Work Calendar</h2><h2 id="ifc-parsing-setup-ifcps"><a class="header-anchor" href="#ifc-parsing-setup-ifcps" aria-hidden="true">#</a> IFC Parsing Setup (IFCPS)</h2><h2 id="machines"><a class="header-anchor" href="#machines" aria-hidden="true">#</a> Machines</h2>',22)];s.render=function(i,t,s,r,l,o){return e(),a("div",null,n)};export{t as __pageData,s as default};
